		// rtt min/avg/max/mdev = 0.028/0.042/0.056/0.014 ms
		// or on macOS:
		// round-trip min/avg/max/stddev = 1.234/2.345/3.456/0.567 ms
		lines := strings.Split(output, "\n")
		for _, line := range lines {
