package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// validateHost checks that the host is a reasonable hostname or IP address
// and does not contain characters that could be used for injection.
func validateHost(host string) error {
	// Allow only alphanumeric characters, dots, hyphens, colons (for IPv6), and square brackets
	validHost := regexp.MustCompile(`^[a-zA-Z0-9.\-:\[\]]+$`)
	if !validHost.MatchString(host) {
		return errors.New("invalid host: contains disallowed characters")
	}
	// Reject hosts that start with a hyphen to prevent argument injection
	if strings.HasPrefix(host, "-") {
		return errors.New("invalid host: must not start with a hyphen")
	}
	if len(host) > 253 {
		return errors.New("invalid host: too long")
	}
	return nil
}

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Validate host to prevent any injection
	if err := validateHost(host); err != nil {
		return 0, err
	}

	// Pass arguments directly to exec.Command to avoid shell injection.
	// Do NOT use "bash -c" with string interpolation.
	countStr := strconv.Itoa(count)
	cmd := exec.Command("ping", "-c", countStr, host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, string(output))
	}

	// Look for the line containing RTT statistics
	outputStr := string(output)
	lines := strings.Split(outputStr, "\n")
	var statsLine string
	for _, line := range lines {
		if strings.Contains(line, "rtt min/avg/max") {
			statsLine = line
			break
		}
	}

	if statsLine == "" {
		return 0, errors.New("could not find RTT statistics in ping output")
	}

	// Extract average latency using regex
	// Example line: rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
	re := regexp.MustCompile(`rtt min/avg/max/mdev = [\d.]+/([\d.]+)/[\d.]+/[\d.]+ ms`)
	matches := re.FindStringSubmatch(statsLine)
	if len(matches) < 2 {
		return 0, errors.New("failed to parse average latency from ping output")
	}

	avgStr := matches[1]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}

	return avg, nil
}

