package main

import (
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}
	if count <= 0 {
		return 0, fmt.Errorf("count must be a positive integer")
	}

	countStr := strconv.Itoa(count)

	var cmd *exec.Cmd
	osType := runtime.GOOS

	switch osType {
	case "windows":
		cmd = exec.Command("ping", "-n", countStr, host)
	default: // linux, darwin, etc.
		cmd = exec.Command("ping", "-c", countStr, host)
	}

	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %v, output: %s", err, string(output))
	}

	outputStr := string(output)

	avgLatency, err := parseAverageLatency(outputStr, osType)
	if err != nil {
		return 0, fmt.Errorf("failed to parse ping output: %v", err)
	}

	return avgLatency, nil
}

func parseAverageLatency(output string, osType string) (float64, error) {
	switch osType {
	case "windows":
		// Windows ping output example:
		// Minimum = 1ms, Maximum = 3ms, Average = 2ms
		re := regexp.MustCompile(`Average\s*=\s*(\d+)ms`)
		matches := re.FindStringSubmatch(output)
		if len(matches) < 2 {
			return 0, fmt.Errorf("could not find average latency in output")
		}
		avg, err := strconv.ParseFloat(matches[1], 64)
		if err != nil {
			return 0, err
		}
		return avg, nil

	default:
		// Linux/macOS ping output example:
		// rtt min/avg/max/mdev = 0.028/0.028/0.028/0.000 ms
		// or: round-trip min/avg/max/stddev = 0.028/0.028/0.028/0.000 ms
		lines := strings.Split(output, "\n")
		for _, line := range lines {
			line = strings.TrimSpace(line)
			if strings.Contains(line, "min/avg/max") {
				// Extract the stats part after '='
				re := regexp.MustCompile(`=\s*([\d.]+)/([\d.]+)/([\d.]+)/([\d.]+)\s*ms`)
				matches := re.FindStringSubmatch(line)
				if len(matches) < 3 {
					return 0, fmt.Errorf("could not parse rtt statistics from line: %s", line)
				}
				// matches[2] is the avg value
				avg, err := strconv.ParseFloat(matches[2], 64)
				if err != nil {
					return 0, err
				}
				return avg, nil
			}
		}
		return 0, fmt.Errorf("could not find rtt statistics in ping output")
	}
}

func main() {
	host := "8.8.8.8"
	count := 4

	fmt.Printf("Pinging %s %d times...\n", host, count)

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}

	fmt.Printf("Average latency to %s: %.2f ms\n", host, avgLatency)
}

